var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"면회시간은 15분. 규정상 연장은 안됩니다.","JPN":"面会時間は15分。規定上、延長はできません。","ENG":"You have 15 minutes. There will be no extensions.","TWN":"面會時間是15分鐘，規定無法加時。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"요청하신대로 녹음은 되지 않을 테니, 문제가 생기면 언제든 호출벨을 누르십시오.","JPN":"要請どおり録音はしませんので、問題がありましたらいつでも呼び出しのベルを押してください。","ENG":"We won’t be recording your visit, like you requested. Should you need any help, please press the pager.","TWN":"照您的吩咐不會進行錄音，要是有什麼問題請按呼叫鈕。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"GUARD_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 배려 감사합니다.","JPN":"はい、お気遣いありがとうございます。","ENG":"Yes, thank you for your kindness.","TWN":"好，謝謝你。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_DELTA_NULL_NULL","text":{"KOREA":"……면회인이 들어갑니다.","JPN":"……面会人、入ります。","ENG":"...Visitor entering.","TWN":"……請進。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"이게 누구십니까? 이런 귀한 분께서 늙은이를 직접 배웅하러 오실 줄이야.","JPN":"これはこれは。尊き方がこの老人のために直接見送りに来てくださるとは。","ENG":"Well, well, well... If it isn’t the great Lady Nanahara herself. Here to bid me farewell?","TWN":"這是誰啊？沒想到會有如此尊貴的人來送我這老頭一程呢。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"돌이키지 못할 짓을 저지르고서도 태도가 뻔뻔하군요, 하바키.","JPN":"取り返しのつかないことをしておいて図々しいですね、覇吐。","ENG":"How are you so shameless after all the things you have done, Habaki?","TWN":"幅木，你做出這種無法挽回的事，還毫無悔意嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그대에겐 죄책감이란 게 없는 건가요?","JPN":"あなたには罪悪感というものがないのですか？","ENG":"Do you not have any remorse in yourself?","TWN":"你難道沒有一絲罪惡感嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"후회라면 하고 있지요.","JPN":"後悔ならしております。","ENG":"As a matter of fact, I do.","TWN":"後悔嗎？當然。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그 노망난 여자와 협력했다가 이 사단이 나고 말았으니 말입니다.","JPN":"あのもうろくした女と協力してこうなってしまいましたからな。","ENG":"I regret cooperating with that damn woman.","TWN":"我後悔跟那個糊塗的女人合作，落得這般下場。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"반성이라곤 없는 자가…… 왜 스스로 관리국에 투항하여 이곳에 갇힌 겁니까?","JPN":"少しの反省もないのに……どうして自ら管理局に投降し、ここに閉じ込められていたのですか？","ENG":"If you do not feel guilty at all... Why did you surrender to the Administration?","TWN":"你根本不懂得反省……又為何要向管理局自首被關在這裡？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"저도 제 목숨 귀한 줄은 아는 놈입니다, 당주님.","JPN":"わしも自分の命の大切さはよく知っております、ご当主。","ENG":"I know my life is important, Lady Nanahara.","TWN":"因為我也是很愛惜生命的，堂主。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"이 철창이 없었다면 하야미의 여식이 진작에 제 목을 쳤겠지요.","JPN":"この鉄格子がなかったなら、速水家の娘がわしの首を討ち取っていたことでしょう。","ENG":"Without these bars, I would have been long past dead in the hands of that Hayami girl.","TWN":"要不是被關在這裡，我早就去向速水的女兒索命！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇게 고개를 들고서 선조들을 뵐 생각은 않는 게 좋을 겁니다.","JPN":"そのように顔を上げてご先祖様にお会いできると思わない方がいいでしょう。","ENG":"You better not think of joining our ancestors with that arrogance.","TWN":"我看你怎麼和祖先交代。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"지당하신 말씀입니다. 이대로 허무하게 끝나서야 저승에 계신 선조를 볼 면목이 없지요.","JPN":"ごもっともです。このまま虚しく終わっては、冥府のご先祖様に合わす顔がありません。","ENG":"Precisely. I wouldn’t be able to look at my ancestors in the eye in the Afterlife. Not when my work ends in vain.","TWN":"您說的是，就這樣空虛地結束，確實無法對在地獄裡的祖先交代。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"사요가 부럽군요. 오로치와 하나가 되어 선조를 뵐 일조차 없어졌으니.","JPN":"小夜がうらやましい。オロチと一つになり、先祖に会うことすらできなくなりましたからな。","ENG":"I would say that I am quite envious of Sayo, though. She wouldn’t have to worry about facing our ancestors, since she became one with Orochi.","TWN":"真羨慕小夜，和大蛇合而為一後，就不用煩惱怎麼跟祖先交代。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나나하라 사요는 그대가 몰래 저지른 그 끔찍한 만행들을 끝내 알아채지 못 했더군요.","JPN":"七原小夜はあなたが秘密裏に行った恐ろしい蛮行に最後まで気付きませんでした。","ENG":"It seems that Nanahara Sayo never noticed the terrible wrongdoings you’ve been performing behind her back.","TWN":"七原小夜到最後都沒發現你背地裡所做的惡行。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그대가 연합 몰래 선대 당주들의 시신을 영지 밖으로 빼돌렸다는 사실을 말이죠.","JPN":"あなたが連合の目を盗んで先代当主の遺体を領地外へ送ったことです。","ENG":"The fact that you smuggled the bodies of the former Head of Nanaharas out of the estate, right under our noses.","TWN":"就是你瞞著聯盟將先祖堂主的屍體移到領地外這件事。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};